const body = $input.first().json.body || $input.first().json;
const from = (body.from || '').replace(/[^+\d]/g, '');
const message = (body.message || '').trim();
const messageId = body.message_id || $execution.id;

if (!from || !message) {
  return [{ json: { valid: false, reason: 'Missing from or message' } }];
}

if (!/^\+370\d{7,8}$/.test(from)) {
  return [{ json: { valid: false, reason: 'Invalid LT phone number', from } }];
}

return [{
  json: {
    valid: true,
    customerPhone: from,
    messageBody: message,
    messageId: messageId,
    receivedAt: new Date().toISOString()
  }
}];

// Load conversation history from static data (keyed by phone)
const staticData = $getWorkflowStaticData('global');
if (!staticData.conversations) {
  staticData.conversations = {};
}

const phone = $input.first().json.customerPhone;
const now = new Date().toISOString();

if (!staticData.conversations[phone]) {
  staticData.conversations[phone] = {
    messages: [],
    startedAt: now,
    bookingStatus: 'none'
  };
}

const conv = staticData.conversations[phone];

// Add incoming message
conv.messages.push({
  role: 'customer',
  content: $input.first().json.messageBody,
  timestamp: now
});

// Keep last 20 messages to avoid overflow
if (conv.messages.length > 20) {
  conv.messages = conv.messages.slice(-20);
}

return [{
  json: {
    customerPhone: phone,
    messageBody: $input.first().json.messageBody,
    messageId: $input.first().json.messageId,
    conversationHistory: conv.messages,
    bookingStatus: conv.bookingStatus,
    isNewConversation: conv.messages.length === 1
  }
}];

// Parse AI response and determine next action
const aiRaw = $input.first().json;

// Handle OpenAI API response format
let aiText = '';
if (aiRaw.choices && aiRaw.choices[0]) {
  aiText = aiRaw.choices[0].message?.content || aiRaw.choices[0].text || '';
} else if (typeof aiRaw === 'string') {
  aiText = aiRaw;
} else {
  aiText = JSON.stringify(aiRaw);
}

aiText = aiText.trim();

// Check if AI returned booking-ready JSON
let bookingReady = false;
let bookingData = null;

try {
  // Try to extract JSON from the response
  const jsonMatch = aiText.match(/\{[\s\S]*"booking_ready"\s*:\s*true[\s\S]*\}/);
  if (jsonMatch) {
    bookingData = JSON.parse(jsonMatch[0]);
    bookingReady = true;
  }
} catch (e) {
  // Not JSON, that's fine — it's a conversation reply
}

const convData = $('Load Conversation History').first().json;

// Save AI reply to conversation history
const staticData = $getWorkflowStaticData('global');
if (staticData.conversations && staticData.conversations[convData.customerPhone]) {
  staticData.conversations[convData.customerPhone].messages.push({
    role: 'assistant',
    content: bookingReady ? 'Registracija patvirtinta!' : aiText,
    timestamp: new Date().toISOString()
  });
  if (bookingReady) {
    staticData.conversations[convData.customerPhone].bookingStatus = 'booked';
  }
}

return [{
  json: {
    bookingReady,
    replyText: bookingReady ? null : aiText,
    bookingData,
    customerPhone: convData.customerPhone,
    messageId: convData.messageId
  }
}];

// Build Google Calendar event from booking data
const booking = $input.first().json.bookingData;
const phone = $input.first().json.customerPhone;

const preferredDate = booking.preferred_date || new Date().toISOString().split('T')[0];
const preferredTime = booking.preferred_time || '09:00';

// Build start time with EET offset
const startISO = `${preferredDate}T${preferredTime}:00+02:00`;

// Calculate end time: +1 hour using string math on local intended time
// Safe for business hours (08:00-17:00), no UTC conversion involved
const [startH, startM] = preferredTime.split(':').map(Number);
const endH = startH + 1;
const endTimeISO = `${preferredDate}T${String(endH).padStart(2, '0')}:${String(startM).padStart(2, '0')}:00+02:00`;

return [{
  json: {
    summary: `Proteros Servisas \u2013 Appointment`,
    description: `KLIENTAS\nVardas: ${booking.client_name || 'Nežinomas'}\nTelefonas: ${phone}\n\nPASLAUGA\nTipas: ${booking.service_type || ''}\nAuto: ${booking.car_info || ''}\nPastabos: ${booking.notes || ''}\n\nSukurta automatiškai per SMS booking agent.`,
    startDateTime: startISO,
    endDateTime: endTimeISO,
    clientName: booking.client_name || '',
    serviceType: booking.service_type || '',
    carInfo: booking.car_info || '',
    customerPhone: phone,
    notes: booking.notes || ''
  }
}];

